import type { RunEvent } from "../../engine/run/events.js";
import type { RunAction } from "../../engine/run/loop.js";
import type {
  ContentRef,
  ParsedTrace,
  TraceHeader,
  TraceTurnRecord,
} from "./types.js";

const isRecord = (value: unknown): value is Record<string, unknown> =>
  value !== null && typeof value === "object" && !Array.isArray(value);

const readString = (
  record: Record<string, unknown>,
  key: string,
  label: string,
): string => {
  const value = record[key];
  if (typeof value !== "string" || value.length === 0) {
    throw new Error(`${label}.${key} must be a non-empty string`);
  }
  return value;
};

const readNumber = (
  record: Record<string, unknown>,
  key: string,
  label: string,
): number => {
  const value = record[key];
  if (typeof value !== "number" || !Number.isInteger(value)) {
    throw new Error(`${label}.${key} must be an integer`);
  }
  return value;
};

const parseContentRef = (value: unknown): ContentRef => {
  if (!isRecord(value)) {
    throw new Error("header.contentRef must be an object");
  }

  const kind = readString(value, "kind", "contentRef");
  const id = readString(value, "id", "contentRef");
  const packVersion =
    value.packVersion === undefined || value.packVersion === null
      ? null
      : typeof value.packVersion === "string"
        ? value.packVersion
        : (() => {
            throw new Error("contentRef.packVersion must be a string or null");
          })();

  return {
    kind: kind as ContentRef["kind"],
    id,
    packVersion,
  };
};

const parseHeader = (value: unknown, lineNumber: number): TraceHeader => {
  if (!isRecord(value)) {
    throw new Error(`line ${lineNumber}: trace header must be a JSON object`);
  }

  if ("turn" in value) {
    throw new Error(`line ${lineNumber}: trace header must not include turn`);
  }

  return {
    protocolVersion: readString(value, "protocolVersion", "header"),
    engineVersion: readString(value, "engineVersion", "header"),
    modelId: readString(value, "modelId", "header"),
    seed: readString(value, "seed", "header"),
    contentRef: parseContentRef(value.contentRef),
    runId: readString(value, "runId", "header"),
    createdAt: readString(value, "createdAt", "header"),
  };
};

const parseAction = (value: unknown, lineNumber: number): RunAction => {
  if (!isRecord(value)) {
    throw new Error(`line ${lineNumber}: action must be a JSON object`);
  }

  const kind = value.kind;
  if (typeof kind !== "string" || kind.length === 0) {
    throw new Error(`line ${lineNumber}: action.kind must be a non-empty string`);
  }

  return value as RunAction;
};

const parseEvents = (value: unknown, lineNumber: number): readonly RunEvent[] => {
  if (!Array.isArray(value)) {
    throw new Error(`line ${lineNumber}: events must be an array`);
  }

  return value as readonly RunEvent[];
};

const parseTurnRecord = (value: unknown, lineNumber: number): TraceTurnRecord => {
  if (!isRecord(value)) {
    throw new Error(`line ${lineNumber}: trace turn must be a JSON object`);
  }

  if (!("turn" in value)) {
    throw new Error(`line ${lineNumber}: trace turn must include turn`);
  }

  return {
    turn: readNumber(value, "turn", "turn"),
    action: parseAction(value.action, lineNumber),
    events: parseEvents(value.events, lineNumber),
    stateHash: readString(value, "stateHash", "turn"),
  };
};

export const parseTraceNdjson = (content: string): ParsedTrace => {
  const lines = content
    .split(/\r?\n/u)
    .map((line) => line.trim())
    .filter((line) => line.length > 0);

  if (lines.length === 0) {
    throw new Error("trace is empty");
  }

  let header: TraceHeader;
  try {
    header = parseHeader(JSON.parse(lines[0] ?? "") as unknown, 1);
  } catch (error) {
    const message = error instanceof Error ? error.message : String(error);
    throw new Error(`line 1: ${message}`);
  }

  const turns: TraceTurnRecord[] = [];

  for (let index = 1; index < lines.length; index += 1) {
    const lineNumber = index + 1;
    const rawLine = lines[index] ?? "";

    let parsed: unknown;
    try {
      parsed = JSON.parse(rawLine) as unknown;
    } catch (error) {
      const message = error instanceof Error ? error.message : String(error);
      throw new Error(`line ${lineNumber}: invalid JSON (${message})`);
    }

    turns.push(parseTurnRecord(parsed, lineNumber));
  }

  return { header, turns };
};

import {
  appendFileSync,
  mkdirSync,
  writeFileSync,
} from "node:fs";

import {
  ENGINE_VERSION,
  PROTOCOL_VERSION,
} from "../../schemas/protocol.js";
import type { EngineLogEvent, GameState } from "../../engine/state/index.js";
import { serialize } from "../../engine/state/index.js";

export type TraceContentRef = {
  readonly providerId: string;
  readonly packVersion: string;
};

export type TraceHeader = {
  readonly recordType: "header";
  readonly protocolVersion: typeof PROTOCOL_VERSION;
  readonly engineVersion: string;
  readonly contentRef: TraceContentRef;
  readonly seed: string;
  readonly createdAt: string;
  readonly runId: string;
};

export type TraceTurnLine<
  Action = unknown,
  Event extends EngineLogEvent = EngineLogEvent,
> = {
  readonly turn: number;
  readonly action: Action;
  readonly events: readonly Event[];
  readonly stateHash: string;
};

export type EngineLikeStepResult<Event extends EngineLogEvent = EngineLogEvent> = {
  readonly state: GameState;
  readonly events: readonly Event[];
};

export type EngineLikeSession<
  Action,
  Event extends EngineLogEvent = EngineLogEvent,
> = {
  readonly state: GameState;
  readonly getAvailableActions?: () => readonly Action[];
  readonly step: (action: Action) => EngineLikeStepResult<Event>;
  readonly isTerminal?: () => boolean;
};

export type RecordedSession<
  Action,
  Event extends EngineLogEvent = EngineLogEvent,
> = EngineLikeSession<Action, Event> & {
  readonly trace: TraceRecorder<Action, Event>;
};

export type TraceRecorderOptions = {
  readonly seed: string;
  readonly createdAt: string;
  readonly contentRef: TraceContentRef;
  readonly runId?: string;
  readonly writer?: TraceWriter;
};

export type TraceRecorder<
  Action = unknown,
  Event extends EngineLogEvent = EngineLogEvent,
> = {
  readonly header: TraceHeader;
  readonly path: string;
  readonly recordTurn: (
    action: Action,
    result: EngineLikeStepResult<Event>,
  ) => TraceTurnLine<Action, Event>;
};

export type TraceWriter = {
  readonly path: string;
  readonly writeHeader: (header: TraceHeader) => void;
  readonly appendTurn: <Action, Event extends EngineLogEvent>(
    line: TraceTurnLine<Action, Event>,
  ) => void;
};

export type TraceFsAdapter = {
  readonly makeDir: (path: string) => void;
  readonly writeNewFile: (path: string, contents: string) => void;
  readonly appendFile: (path: string, contents: string) => void;
};

export type FileTraceWriterOptions = {
  readonly runId: string;
  readonly rootDir?: string;
  readonly fs?: TraceFsAdapter;
};

export const createTraceRecorder = <
  Action,
  Event extends EngineLogEvent = EngineLogEvent,
>(
  options: TraceRecorderOptions,
): TraceRecorder<Action, Event> => {
  const runId = options.runId ?? traceRunId(options.seed, options.createdAt);
  const writer = options.writer ?? createFileTraceWriter({ runId });
  const header: TraceHeader = {
    recordType: "header",
    protocolVersion: PROTOCOL_VERSION,
    engineVersion: ENGINE_VERSION,
    contentRef: options.contentRef,
    seed: options.seed,
    createdAt: options.createdAt,
    runId,
  };

  writer.writeHeader(header);

  return {
    header,
    path: writer.path,
    recordTurn: (action, result) => {
      const line: TraceTurnLine<Action, Event> = {
        turn: result.state.run.turn,
        action,
        events: result.events,
        stateHash: hashState(result.state),
      };
      writer.appendTurn(line);
      return line;
    },
  };
};

export const record = <
  Action,
  Event extends EngineLogEvent = EngineLogEvent,
>(
  session: EngineLikeSession<Action, Event>,
  options: TraceRecorderOptions,
): RecordedSession<Action, Event> => {
  const trace = createTraceRecorder<Action, Event>(options);

  return {
    get state() {
      return session.state;
    },
    getAvailableActions: session.getAvailableActions?.bind(session),
    isTerminal: session.isTerminal?.bind(session),
    step: (action) => {
      const result = session.step(action);
      trace.recordTurn(action, result);
      return result;
    },
    trace,
  };
};

export const createFileTraceWriter = (
  options: FileTraceWriterOptions,
): TraceWriter => {
  const rootDir = trimTrailingSlash(options.rootDir ?? "runs");
  const dir = `${rootDir}/${options.runId}`;
  const path = `${dir}/trace.ndjson`;
  const fs = options.fs ?? nodeTraceFsAdapter;

  return {
    path,
    writeHeader: (header) => {
      fs.makeDir(dir);
      fs.writeNewFile(path, `${JSON.stringify(header)}\n`);
    },
    appendTurn: (line) => {
      fs.appendFile(path, `${JSON.stringify(line)}\n`);
    },
  };
};

export const hashState = (state: GameState): string =>
  hashSerializedState(serialize(state));

export const hashSerializedState = (serialized: string): string => {
  let hash = 0x811c9dc5;

  for (let index = 0; index < serialized.length; index += 1) {
    hash ^= serialized.charCodeAt(index);
    hash = Math.imul(hash, 0x01000193) >>> 0;
  }

  return hash.toString(16).padStart(8, "0");
};

export const traceRunId = (seed: string, createdAt: string): string =>
  `run-${runIdComponent(seed)}-${runIdComponent(createdAt)}`;

const runIdComponent = (value: string): string => {
  const component = value
    .replace(/[^A-Za-z0-9._-]+/g, "-")
    .replace(/^-+|-+$/g, "");

  if (component.length === 0) {
    return "blank";
  }

  return component.slice(0, 80);
};

const trimTrailingSlash = (value: string): string => value.replace(/\/+$/g, "");

const nodeTraceFsAdapter: TraceFsAdapter = {
  makeDir: (path) => {
    mkdirSync(path, { recursive: true });
  },
  writeNewFile: (path, contents) => {
    writeFileSync(path, contents, { encoding: "utf8", flag: "wx" });
  },
  appendFile: (path, contents) => {
    appendFileSync(path, contents, { encoding: "utf8" });
  },
};

