const playShortScript = (seed: string, withRecorder: boolean): string => {
  const baseSession = createFallbackRunSession(seed);
  const session = withRecorder
    ? record(baseSession, {
        seed,
        createdAt: CREATED_AT,
        contentRef: CONTENT_REF,
        writer: memoryWriter(seed),
      })
    : baseSession;

  session.step({ kind: "wait" });
  session.step({ kind: "wait" });
  session.step({ kind: "abort" });

  return hashState(session.state);
};

type MutableRunSession = EngineLikeSession<RunAction, RunEvent> & {
  readonly replaceState: (state: GameState) => void;
};

const createFallbackRunSession = (seed: string): MutableRunSession => {
  const provider = new FallbackFloorContentProvider();
  let state = expectStartedRun(seed, provider);

  return {
    get state() {
      return state;
    },
    step: (action) => {
      const result = stepRun(state, action, provider);
      expect(result.ok, result.ok ? "" : result.error.message).toBe(true);
      if (!result.ok) {
        throw new Error(result.error.message);
      }
      state = result.state;
      return {
        state: result.state,
        events: result.events,
      };
    },
    isTerminal: () => state.run.terminalStatus !== "ACTIVE",
    replaceState: (nextState) => {
      state = nextState;
    },
  };
};

const expectStartedRun = (
  seed: string,
  provider: FloorContentProvider,
): GameState => {
  const started = startRun(seed, provider);
  expect(started.ok, started.ok ? "" : started.error.message).toBe(true);
  if (!started.ok) {
    throw new Error(started.error.message);
  }
  return started.state;
};

const requiredRuntime = (state: GameState) => {
  const runtime = currentFloorRuntime(state);
  expect(runtime).not.toBeNull();
  if (runtime === null) {
    throw new Error("missing run floor runtime");
  }
  return runtime;
};

const withPlayerPosition = (
  state: GameState,
  position: Position,
): GameState => ({
  ...state,
  player: {
    ...state.player,
    position,
  },
});

const memoryWriter = (seed: string) => {
  const runId = traceRunId(seed, CREATED_AT);
  return createFileTraceWriter({
    runId,
    fs: new MemoryTraceFs(),
  });
};

const readTraceLines = (fs: MemoryTraceFs, runId: string): readonly string[] =>
  fs.read(`runs/${runId}/trace.ndjson`).trimEnd().split("\n");

const expectHeader = (line: string | undefined): TraceHeader => {
  expect(line).toBeDefined();
  const parsed = JSON.parse(line ?? "null") as unknown;
  expect(isRecord(parsed)).toBe(true);
  if (!isRecord(parsed) || parsed.recordType !== "header") {
    throw new Error("missing trace header");
  }
  return parsed as TraceHeader;
};

const expectTurnLine = (line: string | undefined): TraceTurnLine<RunAction, RunEvent> => {
  expect(line).toBeDefined();
  const parsed = JSON.parse(line ?? "null") as unknown;
  expect(isRecord(parsed)).toBe(true);
  if (!isRecord(parsed)) {
    throw new Error("missing trace turn line");
  }
  expect(typeof parsed.turn).toBe("number");
  expect(isRecord(parsed.action)).toBe(true);
  expect(Array.isArray(parsed.events)).toBe(true);
  expect(typeof parsed.stateHash).toBe("string");
  return parsed as TraceTurnLine<RunAction, RunEvent>;
};

const isRecord = (value: unknown): value is Record<string, unknown> =>
  value !== null && typeof value === "object" && !Array.isArray(value);

class MemoryTraceFs implements TraceFsAdapter {
  readonly dirs: string[] = [];
  readonly files = new Map<string, string>();

  makeDir(path: string): void {
    this.dirs.push(path);
  }

  writeNewFile(path: string, contents: string): void {
    if (this.files.has(path)) {
      throw new Error(`file already exists: ${path}`);
    }
    this.files.set(path, contents);
  }

  appendFile(path: string, contents: string): void {
    const current = this.files.get(path);
    if (current === undefined) {
      throw new Error(`file does not exist: ${path}`);
    }
    this.files.set(path, current + contents);
  }

  read(path: string): string {
    const contents = this.files.get(path);
    if (contents === undefined) {
      throw new Error(`file does not exist: ${path}`);
    }
    return contents;
  }
}

import { readFileSync } from "node:fs";

import { startRun, stepRun } from "../../engine/run/loop.js";
import { parseTraceNdjson } from "./parse.js";
import { resolveContentProvider } from "./provider.js";
import { computeStateHash } from "./state-hash.js";
import type { DivergenceReport, ParsedTrace, VerifyResult } from "./types.js";

export const replayTrace = (
  trace: ParsedTrace,
): VerifyResult | { readonly status: "unreadable"; readonly error: string } => {
  let provider;
  try {
    provider = resolveContentProvider(trace.header.contentRef);
  } catch (error) {
    const message = error instanceof Error ? error.message : String(error);
    return { status: "unreadable", error: message };
  }

  const started = startRun(trace.header.seed, provider);
  if (!started.ok) {
    return {
      status: "unreadable",
      error: `failed to start run: ${started.error.message}`,
    };
  }

  let state = started.state;

  for (const record of trace.turns) {
    if (state.run.turn !== record.turn) {
      return {
        status: "diverged",
        report: {
          firstDivergentTurn: record.turn,
          expectedHash: record.stateHash,
          actualHash: computeStateHash(state),
        },
      };
    }

    const stepped = stepRun(state, record.action, provider);
    if (!stepped.ok) {
      return {
        status: "unreadable",
        error: `step failed at turn ${record.turn}: ${stepped.error.message}`,
      };
    }

    state = stepped.state;
    const actualHash = computeStateHash(state);

    if (actualHash !== record.stateHash) {
      return {
        status: "diverged",
        report: {
          firstDivergentTurn: record.turn,
          expectedHash: record.stateHash,
          actualHash,
        },
      };
    }
  }

  return { status: "identical" };
};

export const verifyTraceContent = (content: string): VerifyResult => {
  let trace: ParsedTrace;
  try {
    trace = parseTraceNdjson(content);
  } catch (error) {
    const message = error instanceof Error ? error.message : String(error);
    return { status: "unreadable", error: message };
  }

  return replayTrace(trace);
};

export const verify = (tracePath: string): VerifyResult => {
  let content: string;
  try {
    content = readFileSync(tracePath, "utf8");
  } catch (error) {
    const message = error instanceof Error ? error.message : String(error);
    return { status: "unreadable", error: message };
  }

  return verifyTraceContent(content);
};

export type { DivergenceReport, VerifyResult };

import type { RunAction } from "../../engine/run/loop.js";
import type { RunEvent } from "../../engine/run/events.js";

export type ContentRef = {
  readonly kind: "fallback";
  readonly id: string;
  readonly packVersion?: string | null;
};

export type TraceHeader = {
  readonly protocolVersion: string;
  readonly engineVersion: string;
  readonly modelId: string;
  readonly seed: string;
  readonly contentRef: ContentRef;
  readonly runId: string;
  readonly createdAt: string;
};

export type TraceTurnRecord = {
  readonly turn: number;
  readonly action: RunAction;
  readonly events: readonly RunEvent[];
  readonly stateHash: string;
};

export type ParsedTrace = {
  readonly header: TraceHeader;
  readonly turns: readonly TraceTurnRecord[];
};

export type DivergenceReport = {
  readonly firstDivergentTurn: number;
  readonly expectedHash: string;
  readonly actualHash: string;
};

export type VerifyResult =
  | { readonly status: "identical" }
  | { readonly status: "diverged"; readonly report: DivergenceReport }
  | { readonly status: "unreadable"; readonly error: string };

