export type BuildTraceOptions = {
  readonly seed: string;
  readonly actions: readonly RunAction[];
  readonly provider: FloorContentProvider;
  readonly contentRef: ContentRef;
  readonly createdAt: string;
  readonly modelId?: string;
};

export const buildTraceHeader = (
  state: { readonly run: { readonly runId: string; readonly seed: string } },
  options: Pick<
    BuildTraceOptions,
    "contentRef" | "createdAt" | "modelId"
  >,
): TraceHeader => ({
  protocolVersion: PROTOCOL_VERSION,
  engineVersion: ENGINE_VERSION,
  modelId: options.modelId ?? "none",
  seed: state.run.seed,
  contentRef: options.contentRef,
  runId: state.run.runId,
  createdAt: options.createdAt,
});

export const buildTraceFromRun = (options: BuildTraceOptions): string => {
  const started = startRun(options.seed, options.provider);
  if (!started.ok) {
    throw new Error(`failed to start run: ${started.error.message}`);
  }

  const lines: string[] = [
    JSON.stringify(
      buildTraceHeader(started.state, {
        contentRef: options.contentRef,
        createdAt: options.createdAt,
        modelId: options.modelId,
      }),
    ),
  ];

  let state = started.state;

  for (const action of options.actions) {
    const turn = state.run.turn;
    const stepped = stepRun(state, action, options.provider);
    if (!stepped.ok) {
      throw new Error(
        `step failed at turn ${turn} for action ${action.kind}: ${stepped.error.message}`,
      );
    }

    state = stepped.state;
    lines.push(
      JSON.stringify({
        turn,
        action,
        events: stepped.events,
        stateHash: computeStateHash(state),
      }),
    );
  }

  return `${lines.join("\n")}\n`;
};

export type RecordAndVerifyRoundTripOptions = BuildTraceOptions & {
  readonly tracePath?: string;
};

export type RecordAndVerifyRoundTripResult = {
  readonly trace: string;
  readonly verify: VerifyResult;
  readonly tracePath?: string;
};

/**
 * Records a run into NDJSON trace format and immediately verifies byte-identical replay.
 * Use to mint committed golden traces once the 23A recorder lands.
 */
export const recordAndVerifyRoundTrip = (
  options: RecordAndVerifyRoundTripOptions,
): RecordAndVerifyRoundTripResult => {
  const trace = buildTraceFromRun(options);
  const verify = verifyTraceContent(trace);

  if (options.tracePath !== undefined) {
    writeFileSync(options.tracePath, trace, "utf8");
  }

  return {
    trace,
    verify,
    ...(options.tracePath === undefined ? {} : { tracePath: options.tracePath }),
  };
};

import type { FloorContentProvider } from "../../engine/run/loop.js";
