const FALLBACK_PROVIDER_IDS = new Set(["old-stock", "fallback"]);

export const resolveContentProvider = (
  contentRef: ContentRef,
): FloorContentProvider => {
  if (contentRef.kind !== "fallback") {
    throw new Error(`unsupported content ref kind: ${contentRef.kind}`);
  }

  if (!FALLBACK_PROVIDER_IDS.has(contentRef.id)) {
    throw new Error(`unknown fallback content ref id: ${contentRef.id}`);
  }

  return createFallbackFloorContentProvider();
};

