 98	export const createTraceRecorder = <
 99	  Action,
100	  Event extends EngineLogEvent = EngineLogEvent
101	>(
102	  options: TraceRecorderOptions
103	): TraceRecorder<Action, Event> => {
104	  const runId = options.runId ?? traceRunId(options.seed, options.createdAt);
105	  const writer = options.writer ?? createFileTraceWriter({ runId });
106	  const header: TraceHeader = {
107	    recordType: "header",
108	    protocolVersion: PROTOCOL_VERSION,
109	    engineVersion: ENGINE_VERSION,
110	    modelId: options.modelId,
111	    contentRef: options.contentRef,
112	    seed: options.seed,
113	    createdAt: options.createdAt,
114	    runId
