10	export const replayTrace = (
11	  trace: ParsedTrace
12	): VerifyResult | { readonly status: "unreadable"; readonly error: string } => {
13	  let provider;
14	  try {
15	    provider = resolveContentProvider(trace.header.contentRef);
16	  } catch (error) {
17	    const message = error instanceof Error ? error.message : String(error);
18	    return { status: "unreadable", error: message };
19	  }
20	
21	  const started = startRun(trace.header.seed, provider);
22	  if (!started.ok) {
23	    return {
24	      status: "unreadable",
25	      error: `failed to start run: ${started.error.message}`
26	    };
27	  }
28	
29	  let state = started.state;
30	
31	  for (const record of trace.turns) {
32	    const stepped = stepRun(state, record.action, provider);
33	    if (!stepped.ok) {
34	      return {
35	        status: "unreadable",
36	        error: `step failed at turn ${record.turn}: ${stepped.error.message}`
37	      };
38	    }
39	
40	    state = stepped.state;
41	    const actualHash = computeStateHash(state);
42	
43	    // Trace turn numbers use the recorder's post-step state convention.
44	    if (state.run.turn !== record.turn) {
45	      return {
46	        status: "diverged",
47	        report: {
48	          firstDivergentTurn: record.turn,
49	          expectedHash: record.stateHash,
50	          actualHash
51	        }
52	      };
53	    }
54	
55	    if (actualHash !== record.stateHash) {
56	      return {
57	        status: "diverged",
58	        report: {
59	          firstDivergentTurn: record.turn,
60	          expectedHash: record.stateHash,
61	          actualHash
62	        }
63	      };
64	    }
65	  }
66	
67	  return { status: "identical" };
68	};
