109	class MemoryTraceFs implements TraceFsAdapter {
110	  private readonly files = new Map<string, string>();
111	
112	  makeDir(): void {}
113	
114	  writeNewFile(path: string, contents: string): void {
115	    if (this.files.has(path)) {
116	      throw new Error(`file already exists: ${path}`);
117	    }
118	    this.files.set(path, contents);
119	  }
120	
121	  appendFile(path: string, contents: string): void {
122	    const current = this.files.get(path);
123	    if (current === undefined) {
124	      throw new Error(`file does not exist: ${path}`);
125	    }
126	    this.files.set(path, current + contents);
127	  }
128	
129	  read(path: string): string {
130	    const contents = this.files.get(path);
131	    if (contents === undefined) {
132	      throw new Error(`file does not exist: ${path}`);
133	    }
134	    return contents;
135	  }
136	}

