 26	const readNumber = (
 27	  record: Record<string, unknown>,
 28	  key: string,
 29	  label: string
 30	): number => {
 31	  const value = record[key];
 32	  if (typeof value !== "number" || !Number.isInteger(value)) {
 33	    throw new Error(`${label}.${key} must be an integer`);
 34	  }
 35	  return value;
 36	};
