 38	const parseContentRef = (value: unknown): ContentRef => {
 39	  if (!isRecord(value)) {
 40	    throw new Error("header.contentRef must be an object");
 41	  }
 42	
 43	  return {
 44	    providerId: readString(value, "providerId", "contentRef"),
 45	    packVersion: readString(value, "packVersion", "contentRef")
 46	  };
 47	};
