 49	const parseHeader = (value: unknown, lineNumber: number): TraceHeader => {
 50	  if (!isRecord(value)) {
 51	    throw new Error(`line ${lineNumber}: trace header must be a JSON object`);
 52	  }
 53	
 54	  if ("turn" in value) {
 55	    throw new Error(`line ${lineNumber}: trace header must not include turn`);
 56	  }
 57	
 58	  const recordType = readString(value, "recordType", "header");
 59	  if (recordType !== "header") {
 60	    throw new Error(`header.recordType must be "header"`);
 61	  }
 62	
 63	  const protocolVersion = readString(value, "protocolVersion", "header");
 64	  if (protocolVersion !== PROTOCOL_VERSION) {
 65	    throw new Error(`header.protocolVersion must be "${PROTOCOL_VERSION}"`);
 66	  }
 67	
 68	  return {
 69	    recordType,
 70	    protocolVersion,
 71	    engineVersion: readString(value, "engineVersion", "header"),
 72	    modelId: readString(value, "modelId", "header"),
 73	    seed: readString(value, "seed", "header"),
 74	    contentRef: parseContentRef(value.contentRef),
 75	    runId: readString(value, "runId", "header"),
 76	    createdAt: readString(value, "createdAt", "header")
 77	  };
 78	};
