 80	const parseAction = (value: unknown, lineNumber: number): RunAction => {
 81	  if (!isRecord(value)) {
 82	    throw new Error(`line ${lineNumber}: action must be a JSON object`);
 83	  }
 84	
 85	  const kind = value.kind;
 86	  if (typeof kind !== "string" || kind.length === 0) {
 87	    throw new Error(
 88	      `line ${lineNumber}: action.kind must be a non-empty string`
 89	    );
 90	  }
 91	
 92	  return value as RunAction;
 93	};
