109	): TraceTurnRecord => {
110	  if (!isRecord(value)) {
111	    throw new Error(`line ${lineNumber}: trace turn must be a JSON object`);
112	  }
113	
114	  if (!("turn" in value)) {
115	    throw new Error(`line ${lineNumber}: trace turn must include turn`);
116	  }
117	
