126	export const parseTraceNdjson = (content: string): ParsedTrace => {
127	  const lines = content
128	    .split(/\r?\n/u)
129	    .map((line) => line.trim())
130	    .filter((line) => line.length > 0);
131	
132	  if (lines.length === 0) {
133	    throw new Error("trace is empty");
134	  }
135	
136	  let header: TraceHeader;
137	  try {
138	    header = parseHeader(JSON.parse(lines[0] ?? "") as unknown, 1);
139	  } catch (error) {
140	    const message = error instanceof Error ? error.message : String(error);
141	    throw new Error(`line 1: ${message}`);
142	  }
143	
144	  const turns: TraceTurnRecord[] = [];
145	
146	  for (let index = 1; index < lines.length; index += 1) {
147	    const lineNumber = index + 1;
148	    const rawLine = lines[index] ?? "";
149	
150	    let parsed: unknown;
151	    try {
152	      parsed = JSON.parse(rawLine) as unknown;
153	    } catch (error) {
154	      const message = error instanceof Error ? error.message : String(error);
155	      throw new Error(`line ${lineNumber}: invalid JSON (${message})`);
156	    }
157	
158	    turns.push(parseTurnRecord(parsed, lineNumber));
159	  }
160	
161	  return { header, turns };
162	};

