 1	import { serialize, type GameState } from "../../engine/state/index.js";
 2	
 3	const FNV_OFFSET_BASIS = 0x811c9dc5;
 4	const FNV_PRIME = 0x01000193;
 5	
 6	export const computeStateHash = (state: GameState): string =>
 7	  hashSerializedState(serialize(state));
 8	
 9	export const hashSerializedState = (serialized: string): string => {
10	  let hash = FNV_OFFSET_BASIS;
11	
12	  for (let index = 0; index < serialized.length; index += 1) {
13	    hash ^= serialized.charCodeAt(index);
14	    hash = Math.imul(hash, FNV_PRIME) >>> 0;
15	  }
16	
17	  return hash.toString(16).padStart(8, "0");
18	};
